import{_ as e,o as a,c as i,ao as o}from"./chunks/framework.DpRg2CzO.js";const p=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":null}'),r={name:"roadmap.md"};function n(l,t,s,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="Roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#Roadmap" aria-label="Permalink to &quot;Roadmap {#Roadmap}&quot;">​</a></h1><p>GLLVM.jl is being built as a fast Julia <strong>digital twin of <a href="https://itchyshin.github.io/gllvmTMB/" target="_blank" rel="noreferrer"><code>gllvmTMB</code></a></strong>: the same model syntax, usable directly in Julia and (in the future) through R, across all response families. The live, detailed roadmap — with linked issues — is tracked on GitHub:</p><p>➡️ <strong><a href="https://github.com/itchyshin/GLLVM.jl/issues/11" target="_blank" rel="noreferrer">GLLVM.jl roadmap (issue #11)</a></strong></p><h2 id="Phase-release-map" tabindex="-1">Phase → release map <a class="header-anchor" href="#Phase-release-map" aria-label="Permalink to &quot;Phase → release map {#Phase-release-map}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Release</th><th style="text-align:right;">Theme</th><th style="text-align:right;">Highlights</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>v0.1.0</strong></td><td style="text-align:right;">Gaussian complete</td><td style="text-align:right;">closed-form marginal, O(p) phylogenetic fitter, <code>predict</code>/<code>residuals</code>/<code>summary</code>, this docs site</td></tr><tr><td style="text-align:right;"><strong>v0.2.0</strong></td><td style="text-align:right;">Full GLM family + structure</td><td style="text-align:right;">every GLM and two-part family via Laplace, the VA estimator, the ordination trio, covariates / fourth-corner / row effects, the SPDE spatial field and phylogenetic GLM, non-Gaussian CIs, and the <code>gllvm()</code> <code>@formula</code> front-end</td></tr><tr><td style="text-align:right;"><strong>v1.0</strong></td><td style="text-align:right;">Full digital twin</td><td style="text-align:right;">full extractor / ordination / diagnostic parity, ~16 tutorials, the R bridge (<code>engine = &quot;julia&quot;</code>)</td></tr></tbody></table><h2 id="What-works-today" tabindex="-1">What works today <a class="header-anchor" href="#What-works-today" aria-label="Permalink to &quot;What works today {#What-works-today}&quot;">​</a></h2><ul><li><p>Gaussian + phylogenetic GLLVM fitting (closed-form Gaussian marginal).</p></li><li><p>An <strong>O(p)</strong> phylogenetic gradient — exact, linear-in-species scaling.</p></li><li><p><strong>The full GLM response-family set</strong> via a Laplace marginal: Poisson, negative binomial (NB2), Binomial / Bernoulli, Beta, Gamma, Exponential, Ordinal, Tweedie — plus the two-part / mixture families (Delta-lognormal, Delta-Gamma, Hurdle-Poisson, Hurdle-NB, beta-hurdle, ordered-beta, ZIP, ZINB, ZIB).</p></li><li><p>A <strong>variational (VA / ELBO)</strong> estimator alongside Laplace, with VA-based SEs.</p></li><li><p>The <strong>ordination trio</strong> — unconstrained, concurrent (<code>num.lv.c</code>), and constrained / RRR (<code>num.RR</code>) — plus species-specific covariates, fourth-corner trait–environment interactions, fixed community row effects, and quadratic response.</p></li><li><p>Structured latent fields: <strong>SPDE / Matérn spatial</strong> (with kriging prediction) and phylogenetic — including a <strong>phylogenetic GLM</strong> fit (<code>fit_phylo_glm</code>) for non-Gaussian families via an augmented-state joint Laplace.</p></li><li><p>The <strong><code>@formula</code> front-end</strong> (<code>gllvm(...)</code>), offsets, and missing-data (NA) masks.</p></li><li><p>Wald / profile-likelihood / parametric-bootstrap confidence intervals across the Gaussian, GLM, and two-part families (via <code>confint(fit, Y; method=…)</code>), including derived quantities (Σ_y, communality, phylogenetic signal).</p></li></ul><h2 id="What&#39;s-planned" tabindex="-1">What&#39;s planned <a class="header-anchor" href="#What&#39;s-planned" aria-label="Permalink to &quot;What&#39;s planned {#What&#39;s-planned}&quot;">​</a></h2><ul><li><p><strong>Full extractor / ordination / diagnostic parity</strong> with R <code>gllvm</code>, and the remaining <code>@formula</code> terms (<code>traits()</code> / <code>phylo()</code>, random slopes <code>(1+x|g)</code>).</p></li><li><p><strong>The R bridge</strong> — run a <code>gllvmTMB</code> model through the Julia engine (<code>engine = &quot;julia&quot;</code>).</p></li></ul><p>This roadmap evolves; issue #11 is always current.</p>',10)])])}const m=e(r,[["render",n]]);export{p as __pageData,m as default};
